sql:
SELECT researchers.name, researchers.institution
FROM researchers
WHERE researchers.researcher_id IN (
  SELECT user_access.researcher_id
  FROM user_access
);

SELECT COUNT(*)
FROM researchers
INNER JOIN metrics ON researchers.name = metrics.metric_name;

SELECT AVG(impact_factor) AS AverageImpactFactor
FROM reports
WHERE STRFTIME('%Y', publication_date) BETWEEN '2007' AND '2009';

external_knowledge:
- 'More impactful articles' refers to those with an impact factor greater than 3; 
- 'Brief descriptions' correspond to the summary and keywords of the reports;
- Contact details of the authors include their names and email addresses.
